import anthropic

client = anthropic.Anthropic()

# 1. Upload file first
uploaded = client.beta.files.upload(
    file=(
        "contract.pdf",
        open("contract.pdf", "rb"),
        "application/pdf"
    )
)
file_id = uploaded.id  # "file_abc123xyz"

# 2. Reference file_id in Messages request
response = client.beta.messages.create(
    model="claude-opus-4-8",
    max_tokens=16000,
    messages=[{
        "role": "user",
        "content": [
            {"type": "text", "text": "What are the key terms?"},
            {
                "type": "document",  # For PDFs/text files
                "source": {
                    "type": "file",
                    "file_id": file_id  # ← Reference here
                }
            }
        ]
    }]
)

answer = response.content[0].text
print(f"Answer: {answer}")

