import anthropic

client = anthropic.Anthropic()

# Upload multiple files
files = []
for filename in ["contract1.pdf", "contract2.pdf", "contract3.pdf"]:
    uploaded = client.beta.files.upload(
        file=(filename, open(filename, "rb"), "application/pdf")
    )
    files.append(uploaded.id)

# Reference all files in one request
response = client.beta.messages.create(
    model="claude-opus-4-8",
    max_tokens=16000,
    messages=[{
        "role": "user",
        "content": [
            {"type": "text", "text": "Compare these three contracts and identify differences"},
            {
                "type": "document",
                "source": {"type": "file", "file_id": files[0]}
            },
            {
                "type": "document",
                "source": {"type": "file", "file_id": files [github](https://github.com/anthropics/skills/blob/main/skills/claude-api/python/claude-api/files-api.md?plain=1)}
            },
            {
                "type": "document",
                "source": {"type": "file", "file_id": files [platform.claude](https://platform.claude.com/docs/en/api/ruby/beta/files)}
            }
        ]
    }]
)

# Upload multiple images
images = []
for img_path in ["photo1.png", "photo2.png", "photo3.png"]:
    img = client.beta.files.upload(
        file=(img_path, open(img_path, "rb"), "image/png")
    )
    images.append(img.id)

# Reference all images in one request
response = client.beta.messages.create(
    messages=[{
        "role": "user",
        "content": [
            {"type": "text", "text": "Compare these photos and identify differences"},
            {"type": "image", "source": {"type": "file", "file_id": images[0]}},
            {"type": "image", "source": {"type": "file", "file_id": images [github](https://github.com/anthropics/skills/blob/main/skills/claude-api/python/claude-api/files-api.md?plain=1)}},
            {"type": "image", "source": {"type": "file", "file_id": images [platform.claude](https://platform.claude.com/docs/en/api/ruby/beta/files)}}
